function Dashboard() {
    const role = localStorage.getItem("role");

    return (
        <div className="container mt-4">
            <div className="text-center mb-4">
                <h2 className="fw-bold">📊 Dashboard</h2>
                <p className="text-muted">Overview of your activities</p>
            </div>

            {(role === "agent" || role === "admin") && (
                <div className="alert alert-info text-center shadow-sm border-0 rounded-3">
                    <h5 className="mb-0">
                        👋 Welcome back, <span className="fw-bold">{role.charAt(0).toUpperCase() + role.slice(1)}</span>!
                    </h5>
                </div>
            )}
        </div>
    );
}

export default Dashboard;
